import React, { useState } from 'react';
import { Header, Footer } from '../components/layout';
import { InputSection, SummaryCards, ResultsTable } from '../components/calculator';
import { calculateTax } from '../services/taxApi';

function CalculatorPage() {
  const [numEmployees, setNumEmployees] = useState('');
  const [totalSalary, setTotalSalary] = useState('');
  const [results, setResults] = useState(null);
  const [totalTax, setTotalTax] = useState(null);
  const [totalTakeHome, setTotalTakeHome] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleCalculate = async () => {
    setError(null);
    const n = parseInt(numEmployees, 10);
    const total = parseFloat(totalSalary);
    if (!n || n < 1 || !total || total < 0) {
      setError('Enter valid employee count and total salary');
      return;
    }
    setLoading(true);
    try {
      const data = await calculateTax({ numEmployees: n, totalSalary: total });
      setResults(data.employees);
      setTotalTax(data.totalTax);
      setTotalTakeHome(data.totalTakeHome);
    } catch (err) {
      setError(err.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResults(null);
    setTotalTax(null);
    setTotalTakeHome(null);
    setError(null);
  };

  const hasResults = results && results.length > 0;
  const payroll = hasResults ? results.reduce((s, e) => s + e.salary, 0) : 0;
  const effTaxPct = payroll > 0 && totalTax != null ? ((totalTax / payroll) * 100).toFixed(1) : '0';

  return (
    <div className="app">
      <Header />
      <main className="main">
        <InputSection
          numEmployees={numEmployees}
          totalSalary={totalSalary}
          onNumEmployeesChange={setNumEmployees}
          onTotalSalaryChange={setTotalSalary}
          error={error}
          loading={loading}
          onCalculate={handleCalculate}
          onReset={handleReset}
          showReset={hasResults}
        />
        {hasResults && (
          <>
            <SummaryCards
              employeeCount={results.length}
              totalPayroll={payroll}
              totalTax={totalTax}
              totalTakeHome={totalTakeHome}
              effectiveTaxRate={effTaxPct}
            />
            <ResultsTable employees={results} />
          </>
        )}
      </main>
      <Footer />
    </div>
  );
}

export default CalculatorPage;
